const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');
const Joi = require('joi');

const app = express();
app.use(express.json());

const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017';
const DB_NAME = process.env.DB_NAME || 'queryservice';
const COLLECTION_NAME = process.env.COLLECTION_NAME || 'data';

let db;
let collection;

const ALLOWED_OPERATORS = ['$eq', '$ne', '$gt', '$gte', '$lt', '$lte', '$in', '$nin', '$regex', '$exists', '$and', '$or'];
const ALLOWED_FIELDS = ['name', 'email', 'age', 'status', 'createdAt', 'category', 'price', 'quantity', 'description'];
const MAX_QUERY_DEPTH = 3;
const MAX_ARRAY_LENGTH = 100;

const fieldValueSchema = Joi.alternatives().try(
  Joi.string().max(500),
  Joi.number(),
  Joi.boolean(),
  Joi.date(),
  Joi.array().items(
    Joi.alternatives().try(
      Joi.string().max(500),
      Joi.number(),
      Joi.boolean()
    )
  ).max(MAX_ARRAY_LENGTH)
);

const operatorSchema = Joi.object().pattern(
  Joi.string().valid(...ALLOWED_OPERATORS),
  Joi.alternatives().try(
    fieldValueSchema,
    Joi.object().pattern(
      Joi.string().valid('$options'),
      Joi.string().valid('i', 'm', 's', 'x')
    )
  )
);

const queryFieldSchema = Joi.alternatives().try(
  fieldValueSchema,
  operatorSchema
);

const querySchema = Joi.object().pattern(
  Joi.string().valid(...ALLOWED_FIELDS, ...ALLOWED_OPERATORS),
  Joi.alternatives().try(
    queryFieldSchema,
    Joi.array().items(Joi.object()).max(MAX_ARRAY_LENGTH)
  )
);

function sanitizeQuery(query, depth = 0) {
  if (depth > MAX_QUERY_DEPTH) {
    throw new Error('Query depth exceeds maximum allowed');
  }

  if (query === null || query === undefined) {
    return query;
  }

  if (Array.isArray(query)) {
    if (query.length > MAX_ARRAY_LENGTH) {
      throw new Error('Array length exceeds maximum allowed');
    }
    return query.map(item => sanitizeQuery(item, depth + 1));
  }

  if (typeof query === 'object' && !(query instanceof Date) && !(query instanceof RegExp)) {
    const sanitized = {};
    
    for (const [key, value] of Object.entries(query)) {
      if (key.startsWith('$')) {
        if (!ALLOWED_OPERATORS.includes(key)) {
          throw new Error(`Operator ${key} is not allowed`);
        }
        
        if (key === '$regex') {
          if (typeof value !== 'string') {
            throw new Error('$regex value must be a string');
          }
          if (value.length > 500) {
            throw new Error('$regex pattern too long');
          }
          sanitized[key] = value;
        } else if (key === '$options') {
          if (typeof value !== 'string' || !/^[imsx]+$/.test(value)) {
            throw new Error('Invalid $options value');
          }
          sanitized[key] = value;
        } else if (key === '$and' || key === '$or') {
          if (!Array.isArray(value)) {
            throw new Error(`${key} must be an array`);
          }
          sanitized[key] = sanitizeQuery(value, depth + 1);
        } else {
          sanitized[key] = sanitizeQuery(value, depth + 1);
        }
      } else {
        if (!ALLOWED_FIELDS.includes(key)) {
          throw new Error(`Field ${key} is not allowed`);
        }
        sanitized[key] = sanitizeQuery(value, depth + 1);
      }
    }
    
    return sanitized;
  }

  if (typeof query === 'string') {
    if (query.length > 500) {
      throw new Error('String value too long');
    }
    return query;
  }

  if (typeof query === 'number') {
    if (!Number.isFinite(query)) {
      throw new Error('Invalid number value');
    }
    return query;
  }

  if (typeof query === 'boolean') {
    return query;
  }

  throw new Error(`Invalid query value type: ${typeof query}`);
}

function validateAndSanitizeQuery(query) {
  const { error } = querySchema.validate(query, { 
    abortEarly: false,
    stripUnknown: true 
  });
  
  if (error) {
    throw new Error(`Query validation failed: ${error.details.map(d => d.message).join(', ')}`);
  }

  return sanitizeQuery(query);
}

async function connectToDatabase() {
  try {
    const client = await MongoClient.connect(MONGODB_URI, {
      useNewUrlParser: true,
      useUnifiedTopology: true,
    });
    db = client.db(DB_NAME);
    collection = db.collection(COLLECTION_NAME);
    console.log('Connected to MongoDB');
  } catch (error) {
    console.error('MongoDB connection error:', error);
    process.exit(1);
  }
}

app.post('/api/query', async (req, res) => {
  try {
    const { filter = {}, projection = {}, limit = 100, skip = 0, sort = {} } = req.body;

    if (typeof filter !== 'object' || Array.isArray(filter)) {
      return res.status(400).json({ error: 'Filter must be an object' });
    }

    if (typeof projection !== 'object' || Array.isArray(projection)) {
      return res.status(400).json({ error: 'Projection must be an object' });
    }

    if (typeof sort !== 'object' || Array.isArray(sort)) {
      return res.status(400).json({ error: 'Sort must be an object' });
    }

    const sanitizedFilter = validateAndSanitizeQuery(filter);

    const sanitizedProjection = {};
    for (const [key, value] of Object.entries(projection)) {
      if (!ALLOWED_FIELDS.includes(key) && key !== '_id') {
        return res.status(400).json({ error: `Projection field ${key} is not allowed` });
      }
      if (value !== 0 && value !== 1 && value !== false && value !== true) {
        return res.status(400).json({ error: 'Projection values must be 0, 1, false, or true' });
      }
      sanitizedProjection[key] = value;
    }

    const sanitizedSort = {};
    for (const [key, value] of Object.entries(sort)) {
      if (!ALLOWED_FIELDS.includes(key)) {
        return res.status(400).json({ error: `Sort field ${key} is not allowed` });
      }
      if (value !== 1 && value !== -1) {
        return res.status(400).json({ error: 'Sort values must be 1 or -1' });
      }
      sanitizedSort[key] = value;
    }

    const sanitizedLimit = Math.min(Math.max(parseInt(limit) || 100, 1), 1000);
    const sanitizedSkip = Math.max(parseInt(skip) || 0, 0);

    const results = await collection
      .find(sanitizedFilter)
      .project(sanitizedProjection)
      .sort(sanitizedSort)
      .skip(sanitizedSkip)
      .limit(sanitizedLimit)
      .toArray();

    const total = await collection.countDocuments(sanitizedFilter);

    res.json({
      success: true,
      data: results,
      total,
      limit: sanitizedLimit,
      skip: sanitizedSkip
    });

  } catch (error) {
    console.error('Query error:', error.message);
    res.status(400).json({ 
      success: false, 
      error: error.message 
    });
  }
});

